8	import Foundation
9	
10	extension Optional where Wrapped == Float {
11	    func formattedValue(trimZeroes: Bool = false) -> String {
12	        guard let value = self else { return "--" }
13	        switch value {
14	        case 0..<10:
15	            return trimZeroes
16	            ? value.formatted(.number.precision(.fractionLength(0...2)))
17	            : String.localizedStringWithFormat("%.2f", value)
18	        case 10..<100:
19	            return trimZeroes
20	            ? value.formatted(.number.precision(.fractionLength(0...1)))
21	            : String.localizedStringWithFormat("%.1f", value)
22	        case 100..<1000:
23	            return "\(Int(value))"
24	        case 1000..<10_000:
25	            return String(localized: .Localization.formattedThousandDouble(Double(floor(value / 1000 * 10) / 10)))
26	        case 10_000..<1_000_000:
27	            return String(localized: .Localization.formattedThousandInt(Int(value / 1000)))
28	        case 1_000_000...Float.infinity:
29	            return String(localized: .Localization.formattedMillion(Double(floor(value / 1000000 * 10) / 10)))
30	        default:
31	            return "--"
32	        }
33	    }
34	}
